+template<typename T> HoldAny parse_typed_value(boost::property_tree::ptree &pt, const std::string &key){
+    if(pt.count(key) == 0) return HoldAny(TypeGuard::create<T>());
+    return HoldAny(pt.get<T>(key));
+}
