+void read_var(ObjectDict::Entry &entry, boost::property_tree::ptree &object){
+        entry.data_type = int_from_string<uint16_t>(object.get<std::string>("DataType"));
+        entry.mappable = object.get<bool>("PDOMapping", false);
+        set_access(entry, object.get<std::string>("AccessType"));
+        
+        entry.def_val = read_value(object, entry.data_type, "DefaultValue");
+        entry.init_val = read_value(object, entry.data_type, "ParameterValue");
+}
+
+void parse_object(boost::shared_ptr<ObjectDict> dict, boost::property_tree::ptree &pt, const std::string &name, const uint8_t* sub_index = 0){
+        boost::optional<boost::property_tree::ptree&> object =  pt.get_child_optional(name.substr(2));
+        if(!object) return;
+
+        boost::shared_ptr<ObjectDict::Entry> entry = boost::make_shared<ObjectDict::Entry>();
+        entry->index = int_from_string<uint16_t>(name);
+        entry->obj_code = ObjectDict::Code(int_from_string<uint16_t>(object->get<std::string>("ObjectType", boost::lexical_cast<std::string>((uint16_t)ObjectDict::VAR))));
+        entry->desc = object->get<std::string>("Denotation",object->get<std::string>("ParameterName"));
+        
+        // std::cout << name << ": "<< entry->desc << std::endl;
+        if(entry->obj_code == ObjectDict::VAR || entry->obj_code == ObjectDict::DOMAIN_DATA){
+            entry->sub_index = sub_index? *sub_index: 0;
+            read_var(*entry, *object);
+            dict->insert(sub_index != 0, entry);
+        }else if(entry->obj_code == ObjectDict::ARRAY || entry->obj_code == ObjectDict::RECORD){
+            uint8_t subs = object->get<uint8_t>("CompactSubObj",0);
+            if(subs){ // compact
+                dict->insert(true, boost::make_shared<const ipa_canopen::ObjectDict::Entry>(entry->index, 0, ObjectDict::DEFTYPE_UNSIGNED8, "NrOfObjects", true, false, false, HoldAny(subs)));
+
+                read_var(*entry, *object);
+                
+                for(uint8_t i=1; i< subs; ++i){
+                    std::string subname = pt.get<std::string>(name.substr(2)+"Name." + boost::lexical_cast<std::string>((int)i),entry->desc + boost::lexical_cast<std::string>((int)i));
+                    subname = pt.get<std::string>(name.substr(2)+"Denotation." + boost::lexical_cast<std::string>((int)i), subname);
+                    
+                    dict->insert(true, boost::make_shared<const ipa_canopen::ObjectDict::Entry>(entry->index, i, entry->data_type, name, entry->readable, entry->writable, entry->mappable, entry->def_val,
+                       read_value(pt, entry->data_type, name.substr(2)+"Value." + boost::lexical_cast<std::string>((int)i))));
+                }
+            }else{
+                //subs = object->get<uint8_t>("SubNumber");
+                try{
+                    subs = pt.get<uint8_t>(name.substr(2) + "sub0.DefaultValue") + 1;
+                }
+                catch(...){
+                    subs = object->get<uint8_t>("SubNumber");
+                }
+                for(uint8_t i=0; i< subs; ++i){
+                   
+                   parse_object(dict, pt, name + "sub" + boost::lexical_cast<std::string>((int)i), &i);
+                }
+            }
+        }else{
+            throw ParseException();
+        }
+}
+void parse_objects(boost::shared_ptr<ObjectDict> dict, boost::property_tree::ptree &pt, const std::string &key){
+    if(!pt.count(key)) return;
+    
+    boost::property_tree::ptree objects = pt.get_child(key);
+    
+    uint16_t count;
+    read_optional(count, objects, "SupportedObjects");
+    for(uint16_t i=0; i < count; ++i){
+        std::string name = objects.get<std::string>(boost::lexical_cast<std::string>(i+1));
+        parse_object(dict, pt, name);
+    }
+}
+boost::shared_ptr<ObjectDict> ObjectDict::fromFile(const std::string &path){
+    DeviceInfo info;
