+    // check if mapping has to be set
+    if(num <= 0x40){
+        for(uint8_t sub = 1; sub <=num ; ++sub){
+            try{
+                if(!dict(map_index,sub).init_val.is_empty()){
+                    map_changed = true;
+                    break;
+                }
+            }
+            catch (std::out_of_range) {}
